     1→/**
     2→ * Gemini Gateway
     3→ * Streaming response generation with Gemini API
     4→ *
     5→ * Issue #109: Enhanced error handling with ApiError
     6→ */
     7→
     8→import { createGoogleGenerativeAI } from '@ai-sdk/google';
     9→import { streamText, StreamTextResult, CoreMessage } from 'ai';
    10→import { logger } from '@/server/lib/logger';
    11→import { ApiError } from '@/server/lib/middleware/error-handler';
    12→import { getGeminiApiKey, getModelId } from './config';
    13→
    14→interface GeminiConfig {
    15→  model: string; // e.g., 'models/gemini-2.5-flash'
    16→  maxTokens?: number;
    17→  temperature?: number;
    18→}
    19→
    20→const DEFAULT_CONFIG: GeminiConfig = {
    21→  // Stable model supported by v1beta as of 2025-12
    22→  model: 'models/gemini-2.5-flash',
    23→  maxTokens: 2048, // Increased for long list displays
    24→  temperature: 0.3, // FAQ向け低Temperature（回答の一貫性と多少の表現バリエーションを両立）
    25→};
    26→
    27→/**
    28→ * Generate streaming response with Gemini (conversation history supported)
    29→ * @param messages - Conversation history (system, user, assistant messages)
    30→ * @param config - Gemini configuration
    31→ * @throws ApiError on configuration or API errors
    32→ */
    33→export async function generateStreamingResponse(
    34→  messages: CoreMessage[],
    35→  config: GeminiConfig = DEFAULT_CONFIG
    36→): Promise<StreamTextResult<Record<string, never>, never>> {
    37→  const startTime = Date.now();
    38→
    39→  const apiKey = getGeminiApiKey();
    40→  if (!apiKey) {
    41→    // Issue #109: Use ApiError for missing configuration
    42→    throw ApiError.internal(
    43→      'Gemini API key is not configured (GEMINI_API_KEY or GOOGLE_GENERATIVE_AI_API_KEY)'
    44→    );
    45→  }
    46→
    47→  const google = createGoogleGenerativeAI({ apiKey });
    48→
    49→  try {
    50→    const modelId = getModelId(config.model);
    51→    const model = google(modelId);
    52→
    53→    const result = await streamText({
    54→      model,
    55→      messages,
    56→      maxTokens: config.maxTokens,
    57→      temperature: config.temperature,
    58→    });
    59→
    60→    // Latency measurement
    61→    const latency = Date.now() - startTime;
    62→    logger.info({ latency }, 'Gemini response latency');
    63→
    64→    return result;
    65→  } catch (error) {
    66→    // Issue #109: Structured error handling
    67→    const errorInfo = extractErrorInfo(error);
    68→    logger.error({ error: errorInfo }, 'Gemini streaming error');
    69→
    70→    // Retry on rate limit (429) or server errors (5xx)
    71→    if (isRetryableError(error)) {
    72→      logger.info({ code: errorInfo.code }, 'Retrying Gemini request...');
    73→      await sleep(1000);
    74→
    75→      try {
    76→        const modelId = getModelId(config.model);
    77→        const model = google(modelId);
    78→        const result = await streamText({
    79→          model,
    80→          messages,
    81→          maxTokens: config.maxTokens,
    82→          temperature: config.temperature,
    83→        });
    84→
    85→        return result;
    86→      } catch (retryError) {
    87→        const retryInfo = extractErrorInfo(retryError);
    88→        logger.error({ error: retryInfo }, 'Gemini retry failed');
    89→
    90→        // Issue #109: Throw structured ApiError after retry failure
    91→        throw ApiError.serviceUnavailable(
    92→          '一時的に利用できません。しばらくしてからお試しください。'
    93→        );
    94→      }
    95→    }
    96→
    97→    // Issue #109: Wrap unknown errors in ApiError
    98→    if (error instanceof ApiError) {
    99→      throw error;
   100→    }
   101→
   102→    throw ApiError.internal(error instanceof Error ? error.message : 'Unknown Gemini API error');
   103→  }
   104→}
   105→
   106→/**
   107→ * Check if error is retryable (429 or 5xx)
   108→ */
   109→function isRetryableError(error: unknown): boolean {
   110→  if (error instanceof Error) {
   111→    const message = error.message;
   112→    return message.includes('429') || /5\d{2}/.test(message);
   113→  }
   114→  return false;
   115→}
   116→
   117→/**
   118→ * Extract error information for logging
   119→ */
   120→function extractErrorInfo(error: unknown): { message: string; code?: string; stack?: string } {
   121→  if (error instanceof ApiError) {
   122→    return { message: error.message, code: error.code };
   123→  }
   124→  if (error instanceof Error) {
   125→    return { message: error.message, stack: error.stack };
   126→  }
   127→  return { message: String(error) };
   128→}
   129→
   130→/**
   131→ * Sleep utility
   132→ */
   133→function sleep(ms: number): Promise<void> {
   134→  return new Promise(resolve => setTimeout(resolve, ms));
   135→}
